from datetime import date
import unittest

from hello_world import Afternoon, Evening, Greeting, Month, Morning, TimeOfDay, build_output, season_of


# generated by AI in Github cloud
class HelloWorldTest(unittest.TestCase):
    def test_greeting_stores_fields(self) -> None:
        greeting = Greeting("World", "Hello")
        self.assertEqual("World", greeting.recipient)
        self.assertEqual("Hello", greeting.message)

    def test_greeting_formatted_contains_recipient_and_message(self) -> None:
        result = Greeting("Alice", "Hi").formatted()
        self.assertIn("Alice", result)
        self.assertIn("Hi", result)

    def test_greeting_rejects_blank_recipient(self) -> None:
        with self.assertRaises(ValueError):
            Greeting("", "Hello")

    def test_greeting_rejects_blank_message(self) -> None:
        with self.assertRaises(ValueError):
            Greeting("World", "  ")

    def test_time_of_day_morning_for_hour_less_than_12(self) -> None:
        self.assertIsInstance(TimeOfDay.of(0), Morning)
        self.assertIsInstance(TimeOfDay.of(11), Morning)

    def test_time_of_day_afternoon_for_hour_12_to_16(self) -> None:
        self.assertIsInstance(TimeOfDay.of(12), Afternoon)
        self.assertIsInstance(TimeOfDay.of(16), Afternoon)

    def test_time_of_day_evening_for_hour_17_and_above(self) -> None:
        self.assertIsInstance(TimeOfDay.of(17), Evening)
        self.assertIsInstance(TimeOfDay.of(23), Evening)

    def test_season_of_returns_correct_season(self) -> None:
        cases = {
            Month.DECEMBER: "Winter",
            Month.JANUARY: "Winter",
            Month.FEBRUARY: "Winter",
            Month.MARCH: "Spring",
            Month.APRIL: "Spring",
            Month.MAY: "Spring",
            Month.JUNE: "Summer",
            Month.JULY: "Summer",
            Month.AUGUST: "Summer",
            Month.SEPTEMBER: "Autumn",
            Month.OCTOBER: "Autumn",
            Month.NOVEMBER: "Autumn",
        }

        for month, expected in cases.items():
            with self.subTest(month=month):
                self.assertEqual(expected, season_of(month))

    def test_build_output_contains_expected_sections(self) -> None:
        result = build_output(date(2024, 12, 18), "3.12.0")
        self.assertIn("Good evening, World!", result)
        self.assertIn("Python version : 3.12.0", result)
        self.assertIn("Today's date : 2024-12-18 (Winter)", result)


